  quality.score = Math.max(0, quality.score - penalty)
}

import { Project, SyntaxKind, ParameterDeclaration, BindingElement } from "ts-morph";
import * as fs from "node:fs";

const project = new Project({ tsConfigFilePath: "tsconfig.json" });

const sourceFiles = project.getSourceFiles().filter(f => f.getFilePath().includes("scripts/"));

for (const sourceFile of sourceFiles) {
  // Find all parameters
  const params = sourceFile.getDescendantsOfKind(SyntaxKind.Parameter);

  for (const param of params) {
    if (!param.getTypeNode()) {
      const name = param.getName();
      // Destructured parameter like `{ hasSkillMd }`
      if (param.getNameNode().getKind() === SyntaxKind.ObjectBindingPattern) {
        param.setType("Record<string, unknown>");
        continue;
      }

      if (name === "opts" || name === "options" || name === "manifest" || name === "content" || name === "result" || name === "data" || name === "bundle" || name === "frontmatter" || name === "parsed" || name === "item") {
        param.setType("Record<string, unknown>");
      } else if (name === "args" || name === "rules" || name === "skillPaths" || name === "skillNames" || name === "sourceFiles" || name === "groups" || name === "entries") {
        param.setType("string[]");
      } else if (name === "err" || name === "error" || name === "e" || name === "a" || name === "b" || name === "left" || name === "right") {
        param.setType("unknown");
      } else if (name === "i" || name === "max" || name === "priority" || name === "index") {
        param.setType("number");
      } else if (name === "getExtraFrontmatter" || name === "getRuleRef" || name === "getRuleBadges" || name === "getOneLineDesc") {
        param.setType("(...args: unknown[]) => unknown");
      } else {
        param.setType("string");
      }
    }
  }

  // Find all catch clauses
  const catchClauses = sourceFile.getDescendantsOfKind(SyntaxKind.CatchClause);
  for (const clause of catchClauses) {
    const varDecl = clause.getVariableDeclaration();
    if (varDecl && !varDecl.getTypeNode()) {
      varDecl.setType("unknown");
    }
  }
}

project.saveSync();
console.log("Types auto-fixed pass 2.");

import path from "node:path"
import { RULES_DIR } from "./RULES_DIR"
import { listFilesRecursive } from "./lib/fs/listFilesRecursive.js"

export const buildRuleRefSet = async () => {
  const files = await listFilesRecursive(RULES_DIR)
  const refs = new Set()
  for (const file of files) {
    if (!file.endsWith(".mdc")) continue
    const rel = path.relative(RULES_DIR, file).replace(/\\/g, "/")
    refs.add(`@rules/${rel}`)
  }
  return refs
}

import { spawnSync } from "node:child_process"
import path from "node:path"

export const buildZip = (sourceDir: string, targetZip: string) => {
  const parent = path.dirname(sourceDir)
  const folder = path.basename(sourceDir)
  const result = spawnSync("zip", ["-qr", targetZip, folder], {
    cwd: parent,
    stdio: "pipe",
    encoding: "utf8",
  })

  if (result.status !== 0) {
    throw new Error(result.stderr || result.stdout || `Failed to package ${sourceDir}`)
  }
}

// @ts-nocheck
import { readFileSync } from "node:fs"
import { join } from "node:path"
import { skillDirs } from "./skillDirs"
import { violations } from "./violations"
import { parseFrontmatter } from "./lib/skills/parseFrontmatter.js"

export async function main() {
  if (skillDirs.length === 0) {
    console.error("No source skills found under src/skills")
    process.exit(1)
  }
  for (const skillPath of skillDirs) {
    const skillMdPath = join(skillPath, "SKILL.md")
    const content = readFileSync(skillMdPath, "utf8")
    const fm = parseFrontmatter(content)
    if (!fm) {
      violations.push(`${skillMdPath}: missing frontmatter`)
      continue
    }

    const keys = Array.from(fm.fields.keys())
    const unexpected = keys.filter((key: string) => key !== "name" && key !== "description")
    if (unexpected.length > 0) {
      violations.push(`${skillMdPath}: unexpected frontmatter fields (${unexpected.join(", ")})`)
    }
  }
  if (violations.length > 0) {
    console.error("Skill frontmatter contract violations detected:")
    for (const violation of violations) {
      console.error(`- ${violation}`)
    }
    process.exit(1)
  }
  console.log(`Frontmatter contract OK (${skillDirs.length} skills).`)
}

if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(console.error)
}

