export const extractActivationSection = (description: string, startPattern: string | RegExp, endPattern: string | RegExp) => {
  const match = description.match(startPattern)
  if (!match) return ""
  const start = (match.index ?? 0) + match[0].length
  const endMatch = description.slice(start).match(endPattern)
  const end = endMatch ? start + (endMatch.index ?? 0) : description.length
  return description.slice(start, end).trim()
}

// @ts-nocheck
import { readFileSync, writeFileSync } from "node:fs"
import { join } from "node:path"
import { buildLlmsTxt } from "./buildLlmsTxt"
import { LLMS_TXT } from "./LLMS_TXT"
import { skillDirs } from "./skillDirs"
import { skills } from "./skills"
import { parseDescription } from "./lib/skills/parseDescription.js"
import { parseFrontmatter } from "./lib/skills/parseFrontmatter.js"
import { stripQuotes } from "./lib/skills/stripQuotes.js"

export async function main() {
  if (skillDirs.length === 0) {
    console.error("No skill directories found under src/skills/")
    process.exit(1)
  }
  for (const skillPath of skillDirs) {
    const skillMd = join(skillPath, "SKILL.md")
    const content = readFileSync(skillMd, "utf-8")
    const fm = parseFrontmatter(content)
    if (!fm) continue

    const name = stripQuotes(fm.fields.get("name") || "")
    const description = parseDescription(fm.raw)
    if (!name || !description) continue

    skills.push({ name, description, skillPath })
  }
  skills.sort((a: unknown, b: unknown) => a.name.localeCompare(b.name))
  writeFileSync(LLMS_TXT, buildLlmsTxt(skills), "utf-8")
  console.log(`Wrote ${LLMS_TXT} (${skills.length} skills).`)
}

if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(console.error)
}

import { createHash } from "node:crypto"
import { promises as fs } from "node:fs"
import path from "node:path"
import { listFilesRecursive } from "./lib/fs/listFilesRecursive.js"

export const hashDirectory = async (dir: string) => {
  const hash = createHash("sha256")
  const files = await listFilesRecursive(dir)
  const sorted = files.sort((a: string, b: string) => a.localeCompare(b))

  for (const file of sorted) {
    const rel = path.relative(dir, file).replace(/\\/g, "/")
    const content = await fs.readFile(file)
    hash.update(rel)
    hash.update("\0")
    hash.update(content)
    hash.update("\0")
  }

  return hash.digest("hex")
}

// @ts-nocheck
import { promises as fs } from "node:fs"
import path from "node:path"
import { defaultIsIgnored } from "./defaultIsIgnored"

export const listFilesRecursive = async (dirPath: string, isIgnored: string = defaultIsIgnored) => {
  const entries = await fs.readdir(dirPath, { withFileTypes: true })
  const results = []

  for (const entry of entries) {
    if (isIgnored(entry.name)) {
      continue
    }

    const fullPath = path.join(dirPath, entry.name)

    if (entry.isDirectory()) {
      const nested = await listFilesRecursive(fullPath, isIgnored)
      results.push(...nested)
      continue
    }

    if (entry.isFile()) {
      results.push(fullPath)
    }
  }

  return results.sort((a: unknown, b: unknown) => a.localeCompare(b))
}

