export function extractShortSummaryLine(content: Record<string, unknown>) {
  const text = String(content || "")
  const match = /##\s+Short summary\s*\n([\s\S]*?)(?=\n##\s|\n#\s|$)/i.exec(text)
  if (!match) return ""
  const block = match[1] || ""
  const lines = block
    .split("\n")
    .map((l: string) => l.trim())
    .filter(Boolean)
  const bullet = lines.find((l: string) => l.startsWith("- ") || l.startsWith("* "))
  if (bullet) return bullet.replace(/^[-*]\s+/, "")
  return lines[0] || ""
}

