/** Normalize line endings to \\n for stable diffs and cross-platform consistency. */
export function normalizeLineEndings(content: string) {
  return String(content ?? "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
}

export function normalizeRel(rel: string) {
  const s = String(rel ?? "")
    .replace(/\\/g, "/")
    .replace(/^\/+/, "")
  return s.replace(/(^|\/)\.\.(?=\/|$)/g, "")
}

