import { promises as fs } from "node:fs"
import path from "node:path"
import { ensureDir } from "../fs/ensureDir.js"
import { normalizeRel } from "./normalizeRel.js"
import { toClaudeRule } from "./toClaudeRule.js"

export const syncClaudeRules = async (sourceFiles: string[], sourceDir: string, claudeRulesDir: string) => {
  await fs.rm(claudeRulesDir, { recursive: true, force: true })
  await ensureDir(claudeRulesDir)

  const mdcFiles = sourceFiles
    .filter((sourcePath: string) => sourcePath.endsWith(".mdc"))
    .sort((a: string, b: string) => a.localeCompare(b))

  for (const sourcePath of mdcFiles) {
    const relativePath = normalizeRel(sourceDir, sourcePath).replace(/\.mdc$/, ".md")
    const targetPath = path.join(claudeRulesDir, relativePath)
    const sourceContent = await fs.readFile(sourcePath, "utf8")
    const claudeContent = `${toClaudeRule(sourceContent)}\n`

    await ensureDir(path.dirname(targetPath))
    await fs.writeFile(targetPath, claudeContent, "utf8")
  }
}

import { convertToAntigravityMentions } from "./antigravity/convertToAntigravityMentions.js"
import { detectUmbrellaType } from "./antigravity/detectUmbrellaType.js"
import { generateAntigravityHeader } from "./antigravity/generateAntigravityHeader.js"
import { getAntigravityActivation } from "./antigravity/getAntigravityActivation.js"
import { splitForAntigravity } from "./antigravity/splitForAntigravity.js"

/**
 * Main conversion function
 * @param {object} parsed - Parsed MDC with frontmatter and content
 * @param {string} rulePath - Original rule path
 * @returns {Array<{name: string, content: string, isWorkflow: boolean}>}
 */
export function toAntigravityRule(parsed: any, rulePath: string) {
  const activation = getAntigravityActivation(parsed.frontmatter)
  const header = generateAntigravityHeader(parsed.frontmatter, activation)
  const content = convertToAntigravityMentions(parsed.content, rulePath)
  const umbrellaInfo = detectUmbrellaType(parsed, rulePath)
  const fullContent = header + content
  const ruleName = rulePath.replace(/\.mdc$/, "").replace(/\//g, "-")
  const parts = splitForAntigravity(fullContent, ruleName)
  return parts.map((part: any) => ({
    ...part,
    isWorkflow: umbrellaInfo.isWorkflow,
  }))
}

