import { stripQuotes } from "./stripQuotes"

export const parseDescription = (frontmatterRaw: string) => {
  const lines = frontmatterRaw.split(/\r?\n/)
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]
    if (!line || !line.startsWith("description:")) continue

    const initial = line.replace(/^description:\s*/, "").trim()
    if (initial.length > 0) return stripQuotes(initial)

    const values = []
    for (let j = i + 1; j < lines.length; j++) {
      const next = lines[j]
      if (!next || /^[A-Za-z0-9_-]+:\s*/.test(next)) break
      if (next.trim().length === 0) break
      values.push(next.trim())
    }

    return values.join(" ").trim()
  }

  return ""
}

import { FRONTMATTER_RE } from "./FRONTMATTER_RE"

export const parseFrontmatter = (content: string) => {
  const match = content.match(FRONTMATTER_RE)
  if (!match) return null

  const raw = match[1]
  if (!raw) return null
  const lines = raw.split(/\r?\n/)
  const fields = new Map()

  for (const line of lines) {
    const simple = line.match(/^([A-Za-z0-9_-]+):\s*(.*)$/)
    if (simple && simple[1] !== undefined && simple[2] !== undefined) {
      fields.set(simple[1], simple[2].trim())
    }
  }

  return { raw, lines, fields }
}

import { matchBoolean } from "./matchBoolean"
import { matchValue } from "./matchValue"
import { stripQuotes } from "./stripQuotes"

export const parseOpenAiYamlContent = (content: string) => {
  const interfaceDisplayName = stripQuotes(matchValue(content, /^\s{2}display_name:\s*(.+)\s*$/m))
  const interfaceShortDescription = stripQuotes(
    matchValue(content, /^\s{2}short_description:\s*(.+)\s*$/m),
  )
  const interfaceDefaultPrompt = stripQuotes(
    matchValue(content, /^\s{2}default_prompt:\s*(.+)\s*$/m),
  )
  const interfaceBrandColor = stripQuotes(matchValue(content, /^\s{2}brand_color:\s*(.+)\s*$/m))
  const interfaceIconSmall = stripQuotes(matchValue(content, /^\s{2}icon_small:\s*(.+)\s*$/m))
  const interfaceIconLarge = stripQuotes(matchValue(content, /^\s{2}icon_large:\s*(.+)\s*$/m))
  const allowImplicitInvocation = matchBoolean(
    content,
    /^\s{2}allow_implicit_invocation:\s*(.+)\s*$/m,
  )
  const skillClass = stripQuotes(matchValue(content, /^\s{2}skill_class:\s*(.+)\s*$/m))
  const requiresReferences = matchBoolean(content, /^\s{2}requires_references:\s*(.+)\s*$/m)
  const failureMode = stripQuotes(matchValue(content, /^\s{2}failure_mode:\s*(.+)\s*$/m))
  const toolDependencyCount = (content.match(/^\s{4}- type:\s*(.+)\s*$/gm) || []).length

  return {
    raw: content,
    interface: {
      hasSection: /^interface:\s*$/m.test(content),
      displayName: interfaceDisplayName,
      shortDescription: interfaceShortDescription,
      defaultPrompt: interfaceDefaultPrompt,
      brandColor: interfaceBrandColor,
      iconSmall: interfaceIconSmall,
      iconLarge: interfaceIconLarge,
    },
    policy: {
      hasSection: /^policy:\s*$/m.test(content),
      allowImplicitInvocation,
    },
    busirocket: {
      hasSection: /^busirocket:\s*$/m.test(content),
      skillClass,
      requiresReferences,
      failureMode,
    },
    dependencies: {
      hasSection: /^dependencies:\s*$/m.test(content),
      hasToolsSection: /^\s{2}tools:\s*$/m.test(content),
      toolDependencyCount,
    },
  }
}

import { FRONTMATTER_RE } from "./FRONTMATTER_RE"

export const replaceFrontmatter = (content: string, nextFrontmatter: string) => {
  const match = content.match(FRONTMATTER_RE)
  if (!match) {
    return `---\n${nextFrontmatter}\n---\n\n${content.trimStart()}`
  }

  return content.replace(FRONTMATTER_RE, `---\n${nextFrontmatter}\n---`)
}

// @ts-nocheck

export const validateSkillRulesManifestShape = (manifest: Record<string, unknown>) => {
  const errors = []
  const warnings = []

  if (!manifest || typeof manifest !== "object") {
    return { errors: ["Manifest must be a JSON object."], warnings }
  }

  if (!Number.isInteger(manifest.version)) {
    errors.push("Manifest field 'version' must be an integer.")
  }

  if (!manifest.skills || typeof manifest.skills !== "object" || Array.isArray(manifest.skills)) {
    errors.push("Manifest field 'skills' must be an object map.")
    return { errors, warnings }
  }

  for (const [skillName, entry] of Object.entries(manifest.skills)) {
    if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
      errors.push(`Manifest entry '${skillName}' must be an object.`)
      continue
    }

    if (!Array.isArray(entry.rules)) {
      errors.push(`Manifest entry '${skillName}' must include a 'rules' array.`)
      continue
    }

    if (entry.rules.length === 0) {
      errors.push(`Manifest entry '${skillName}' must have at least one rule.`)
      continue
    }

    const seen = new Set()
    for (const rule of entry.rules) {
      if (typeof rule !== "string" || rule.trim().length === 0) {
        errors.push(`Manifest entry '${skillName}' contains an empty rule reference.`)
        continue
      }

      if (!rule.startsWith("@rules/")) {
        errors.push(`Manifest entry '${skillName}' contains non @rules reference: ${rule}`)
      }

      if (seen.has(rule)) {
        errors.push(`Manifest entry '${skillName}' contains duplicate rule reference: ${rule}`)
      }
      seen.add(rule)
    }
  }

  return { errors, warnings }
}

